package com.enterprise.spark.gpu.core.data import com.enterprise.spark.gpu.core.SparkGpuTestBase
import org.apache.spark.sql.functions._ /** * Comprehensive test suite for SyntheticDataGenerator. * * This test suite validates: * - Data generation functionality with realistic datasets * - Data quality and statistical validity * - Performance characteristics and execution times * - File I/O operations and data persistence * - Error handling and edge cases * * Tests are designed to run quickly while providing comprehensive coverage * of the data generation functionality. */
class SyntheticDataGeneratorTest extends SparkGpuTestBase { private var dataGenerator: SyntheticDataGenerator = _ override def beforeEach(): Unit = { super.beforeEach() dataGenerator = new SyntheticDataGenerator(spark) } test("should generate taxi dataset with correct schema and record count") { val config = createTestConfig(taxiRecords = 1000, housingRecords = 500) val (summary, executionTime) = measureExecutionTime { dataGenerator.generateAllDatasets(config) } // Verify summary information summary.taxiRecords shouldEqual 1000 summary.housingRecords shouldEqual 500 summary.totalRecords shouldEqual 1500 summary.validationResults.valid shouldBe true // Load and verify taxi dataset val taxiData = spark.read.parquet(summary.taxiFilePath) // Verify record count assertRecordCount(taxiData, 1000) // Verify schema val expectedTaxiColumns = Seq( "trip_id", "trip_date", "hour_of_day", "day_of_week", "pickup_latitude", "pickup_longitude", "dropoff_latitude", "dropoff_longitude", "trip_distance_meters", "fare_amount", "passenger_count", "tip_indicator" ) assertColumns(taxiData, expectedTaxiColumns) // Verify no null values assertNoNulls(taxiData, expectedTaxiColumns) // Verify data ranges and quality val stats = taxiData.agg( min("hour_of_day").as("min_hour"), max("hour_of_day").as("max_hour"), min("fare_amount").as("min_fare"), avg("fare_amount").as("avg_fare"), min("passenger_count").as("min_passengers"), max("passenger_count").as("max_passengers") ).collect()(0) // Hour should be 0-23 stats.getInt(0) should be >= 0 stats.getInt(1) should be <= 23 // Fare should be positive stats.getDouble(2) should be > 0.0 stats.getDouble(3) should be > 0.0 // Passenger count should be 1-5 stats.getInt(4) should be >= 1 stats.getInt(5) should be <= 5 logTestPerformance("Taxi Dataset Generation", executionTime, 1000) } test("should generate housing dataset with correct schema and realistic data") { val config = createTestConfig(taxiRecords = 500, housingRecords = 1000) val (summary, executionTime) = measureExecutionTime { dataGenerator.generateAllDatasets(config) } // Load and verify housing dataset val housingData = spark.read.parquet(summary.housingFilePath) // Verify record count assertRecordCount(housingData, 1000) // Verify schema val expectedHousingColumns = Seq( "house_id", "price", "total_rooms", "bedrooms", "bathrooms", "square_feet", "age_years", "distance_to_center_km", "crime_rate", "school_rating", "neighborhood", "property_type" ) assertColumns(housingData, expectedHousingColumns) // Verify no null values in numeric columns val numericColumns = Seq("house_id", "price", "total_rooms", "bedrooms", "bathrooms", "square_feet", "age_years", "distance_to_center_km", "crime_rate", "school_rating") assertNoNulls(housingData, numericColumns) // Verify data quality and realistic ranges val stats = housingData.agg( min("price").as("min_price"), max("price").as("max_price"), avg("price").as("avg_price"), min("total_rooms").as("min_rooms"), max("total_rooms").as("max_rooms"), min("school_rating").as("min_school"), max("school_rating").as("max_school") ).collect()(0) // Price should be reasonable stats.getDouble(0) should be >= 50000.0 // Minimum price threshold stats.getDouble(1) should be <= 2000000.0 // Maximum reasonable price stats.getDouble(2) should be >= 100000.0 // Average should be reasonable // Rooms should be 2-7 stats.getInt(3) should be >= 2 stats.getInt(4) should be <= 7 // School rating should be 1-10 stats.getInt(5) should be >= 1 stats.getInt(6) should be <= 10 // Verify categorical data val neighborhoods = housingData.select("neighborhood").distinct().collect().map(_.getString(0)) neighborhoods should contain allOf ("Downtown", "Suburbs", "Waterfront", "Historic", "Industrial") val propertyTypes = housingData.select("property_type").distinct().collect().map(_.getString(0)) propertyTypes should contain allOf ("Single Family", "Condo", "Townhouse", "Duplex") logTestPerformance("Housing Dataset Generation", executionTime, 1000) } test("should validate data quality correctly") { val config = createTestConfig(taxiRecords = 100, housingRecords = 100) config.copy(enableDataValidation = true) val summary = dataGenerator.generateAllDatasets(config) // Validation should pass for clean generated data summary.validationResults.valid shouldBe true summary.validationResults.message should include("Validation passed") } test("should handle different record counts efficiently") { val testCases = Seq( (100, 50), (1000, 500), (5000, 2500) ) testCases.foreach { case (taxiRecords, housingRecords) => val config = createTestConfig(taxiRecords = taxiRecords, housingRecords = housingRecords) val (summary, executionTime) = measureExecutionTime { dataGenerator.generateAllDatasets(config) } summary.taxiRecords shouldEqual taxiRecords summary.housingRecords shouldEqual housingRecords // Verify files exist assertPathExists(summary.taxiFilePath) assertPathExists(summary.housingFilePath) // Performance should scale reasonably (not more than linear) val recordsPerMs = summary.totalRecords.toDouble / executionTime recordsPerMs should be > 0.1 // At least 0.1 records per millisecond logTestPerformance(s"Generation ($taxiRecords taxi, $housingRecords housing)", executionTime, summary.totalRecords) } } test("should generate realistic temporal patterns in taxi data") { val config = createTestConfig(taxiRecords = 10000, housingRecords = 100) val summary = dataGenerator.generateAllDatasets(config) val taxiData = spark.read.parquet(summary.taxiFilePath) // Analyze hourly distribution val hourlyStats = taxiData .groupBy("hour_of_day") .agg(count("*").as("trip_count")) .orderBy("hour_of_day") .collect() // Should have trips in all 24 hours hourlyStats.length shouldEqual 24 // Peak hours (7-9 AM, 5-7 PM) should have more trips than off-peak hours (2-4 AM) val peakHours = hourlyStats.filter(row => { val hour = row.getInt(0) (hour >= 7 && hour <= 9) || (hour >= 17 && hour <= 19) }).map(_.getLong(1)) val offPeakHours = hourlyStats.filter(row => { val hour = row.getInt(0) hour >= 2 && hour <= 4 }).map(_.getLong(1)) if (peakHours.nonEmpty && offPeakHours.nonEmpty) { val avgPeakTrips = peakHours.sum / peakHours.length val avgOffPeakTrips = offPeakHours.sum / offPeakHours.length // Peak hours should have more trips (allowing for some randomness) avgPeakTrips should be >= (avgOffPeakTrips * 0.8) } } test("should generate correlated features in housing data") { val config = createTestConfig(taxiRecords = 100, housingRecords = 5000) val summary = dataGenerator.generateAllDatasets(config) val housingData = spark.read.parquet(summary.housingFilePath) // Calculate correlations between related features import org.apache.spark.sql.functions._ // Rooms and bedrooms should be positively correlated val roomsBedroomsCorr = housingData.stat.corr("total_rooms", "bedrooms") roomsBedroomsCorr should be > 0.3 // Square feet and rooms should be positively correlated val sizeFeetRoomsCorr = housingData.stat.corr("square_feet", "total_rooms") sizeFeetRoomsCorr should be > 0.3 // Age and price should be negatively correlated (older houses cost less) val agePriceCorr = housingData.stat.corr("age_years", "price") agePriceCorr should be < 0.1 // Should be negative or close to zero // School rating and price should be positively correlated val schoolPriceCorr = housingData.stat.corr("school_rating", "price") schoolPriceCorr should be > 0.1 } test("should handle edge cases and error conditions gracefully") { // Test with very small dataset val smallConfig = createTestConfig(taxiRecords = 1, housingRecords = 1) val smallSummary = dataGenerator.generateAllDatasets(smallConfig) smallSummary.taxiRecords shouldEqual 1 smallSummary.housingRecords shouldEqual 1 smallSummary.validationResults.valid shouldBe true // Verify files exist and contain data val taxiData = spark.read.parquet(smallSummary.taxiFilePath) val housingData = spark.read.parquet(smallSummary.housingFilePath) taxiData.count() shouldEqual 1 housingData.count() shouldEqual 1 } test("should generate deterministic data for reproducibility") { val config1 = createTestConfig(taxiRecords = 1000, housingRecords = 500) val config2 = config1.copy(outputDirectory = testOutputDirectory + "/run2") // Generate data twice with same parameters val summary1 = dataGenerator.generateAllDatasets(config1) val summary2 = dataGenerator.generateAllDatasets(config2) // Load both datasets val taxi1 = spark.read.parquet(summary1.taxiFilePath) val taxi2 = spark.read.parquet(summary2.taxiFilePath) // Compare first few records to verify deterministic generation val taxi1Sample = taxi1.orderBy("trip_id").limit(10).collect() val taxi2Sample = taxi2.orderBy("trip_id").limit(10).collect() taxi1Sample.zip(taxi2Sample).foreach { case (row1, row2) => row1.getInt(0) shouldEqual row2.getInt(0) // trip_id should match row1.getDouble(8) shouldEqual row2.getDouble(8) // trip_distance should match row1.getInt(10) shouldEqual row2.getInt(10) // passenger_count should match } } test("should measure and report generation performance") { val config = createTestConfig(taxiRecords = 2000, housingRecords = 1000) val (summary, totalTime) = measureExecutionTime { dataGenerator.generateAllDatasets(config) } // Verify performance metrics are captured summary.generationTimeMs should be > 0L summary.generationTimeMs should be <= totalTime + 100 // Allow small variance // Performance should be reasonable (at least 100 records per second) val recordsPerSecond = (summary.totalRecords * 1000.0) / summary.generationTimeMs recordsPerSecond should be >= 100.0 logTestPerformance("Performance Measurement Test", totalTime, summary.totalRecords) }
}